-    error_detail: url.replace(/^wss?:\/\/[^/]+/, '').slice(0, 100),
-    error_page: typeof window !== 'undefined' ? window.location.pathname : '',
-  })
+  emitError('ws_auth_missing', url.replace(/^wss?:\/\/[^/]+/, '').slice(0, 100))
 }

